import { useRef } from "react"
import { a11y, page, render } from "#test/browser"
import { Portal } from "./portal"

describe("<Portal />", () => {
  test("renders component correctly", async () => {
    await a11y(<Portal>Hello</Portal>)
  })

  test("sets `displayName` correctly", () => {
    expect(Portal.name).toBe("Portal")
  })

  test("Portal with containerRef renders correctly", async () => {
    const TestContainer = () => {
      const ref = useRef<HTMLDivElement>(null)

      return (
        <div>
          order1
          <Portal containerRef={ref}>order3</Portal>
          <div ref={ref}>order2</div>
        </div>
      )
    }

    await render(<TestContainer />)

    await expect.element(page.getByText("order2order3")).toBeInTheDocument()
  })

  test("Nested Portal with containerRef renders correctly", async () => {
    const TestContainer = () => {
      const ref = useRef<HTMLDivElement>(null)

      return (
        <>
          <Portal containerRef={ref}>
            order2
            <Portal>order3</Portal>
          </Portal>
          <div ref={ref}>order1</div>
        </>
      )
    }

    await render(<TestContainer />)

    await expect.element(page.getByText("order1order2")).toBeInTheDocument()
    await expect.element(page.getByText("order3")).toBeInTheDocument()
  })

  test("Portal with disabled renders correctly", async () => {
    const TestContainer = () => {
      const ref = useRef<HTMLDivElement>(null)

      return (
        <>
          <Portal containerRef={ref} disabled>
            order2
          </Portal>
          <div ref={ref}>order1</div>
        </>
      )
    }

    await render(<TestContainer />)

    await expect
      .element(page.getByText("order1"))
      .not.toHaveTextContent("order1order2")
  })
})

"use client"

import type { FC, PropsWithChildren, RefObject } from "react"
import type { RootNode } from "@yamada-ui/react"
import { Children, useEffect, useState } from "react"
import { createPortal } from "react-dom"
import { useEnvironment, getDocument, isShadowRoot, useSsr } from "@yamada-ui/react"

const getPortalNode = (node?: RootNode) => {
  const rootNode = node?.getRootNode()

  if (isShadowRoot(rootNode)) return rootNode

  return getDocument(node).body
}

export interface PortalProps extends PropsWithChildren {
  /**
   * The `ref` to the component where the portal will be attached to.
   */
  containerRef?: RefObject<HTMLElement | null>
  /**
   * If `true`, the forwarding will be disabled.
   */
  disabled?: boolean
}

/**
 * `Portal` is a component that renders elements outside of the current `DOM` hierarchy.
 *
 * @see https://yamada-ui.com/docs/components/portal
 */
export const Portal: FC<PortalProps> = ({
  children,
  containerRef: ref,
  disabled,
}) => {
  const [target, setTarget] = useState(ref?.current)
  const ssr = useSsr()
  const { getRootNode } = useEnvironment()

  useEffect(() => {
    setTarget(() => ref?.current)
  }, [ref])

  if (ssr || disabled) return children

  const container = target ?? getPortalNode(getRootNode())

  return (
    <>{Children.map(children, (child) => createPortal(child, container))}</>
  )
}
